use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:               ByteArray,
  collateral_lovelace: Int,
  debt_lovelace:       Int,
  liquidation_ratio:   Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

/// True when the position is undercollateralized (eligible for liquidation)
fn is_undercollateralized(
  collateral: Int,
  debt:       Int,
  ratio:      Int,
) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator must send at least debt_lovelace to the owner
fn liquidator_pays_debt(
  outputs:        List<Output>,
  owner_addr:     Output,
  debt_lovelace:  Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_liquidation {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay ->
        // Owner repays: they must sign
        list.has(self.extra_signatories, d.owner)
      Liquidate ->
        // Anyone can liquidate when undercollateralized
        is_undercollateralized(
          d.collateral_lovelace,
          d.debt_lovelace,
          d.liquidation_ratio,
        )
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  // collateral = debt * 119/100 < debt * 120/100 → undercollateralized at ratio 120
  is_undercollateralized(debt * 119, debt * 100, 120)
}

test prop_not_undercollateralized_above_ratio(debt via fuzz.int_at_least(1)) {
  !is_undercollateralized(debt * 150, debt * 100, 120)
}

test prop_undercollateralized_always_requires_debt(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_at_least(1)),
) {
  let (collateral, ratio) = vals
  !is_undercollateralized(collateral, 0, ratio)
}

test prop_undercollateralized_inverse_of_overcollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (collateral, debt) = vals
  let ratio = 150
  let under = is_undercollateralized(collateral, debt, ratio)
  let over  = collateral * 100 >= debt * ratio
  // They cannot both be true simultaneously
  !(under && over)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// A well-collateralized position (collateral * 100 >= debt * ratio) must NOT
/// be flagged as undercollateralized.
test prop_overcollateralized_not_undercollateralized(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral = debt * 200, ratio = 150 → 200*100=20000 >= 150*100=15000 → safe
  expect is_undercollateralized(debt * 200, debt * 100, 150)
}

/// Zero debt can never be undercollateralized, regardless of collateral / ratio.
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 500)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

/// An empty output list can never satisfy a positive debt payment.
test prop_no_outputs_liquidator_pays_nothing(
  debt via fuzz.int_at_least(1),
) fail {
  // With no outputs the paid amount is 0, which is < any positive debt
  expect liquidator_pays_debt([], Output { address: builtin.serialise_data(#""), value: assets.zero, datum: transaction.NoDatum, reference_script: None }, debt)
}

/// Exact collateral equal to the threshold is NOT undercollateralized
/// (boundary condition: collateral * 100 == debt * ratio → safe, not under).
test prop_boundary_collateral_not_undercollateralized(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral * 100 == debt * ratio  →  is_undercollateralized should be False
  let ratio = 150
  expect is_undercollateralized(debt * ratio, debt * 100, ratio)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  bonus_percent:     Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator pays discounted debt: debt * (100 - bonus_percent) / 100
fn discounted_debt(debt: Int, bonus_percent: Int) -> Int {
  debt * (100 - bonus_percent) / 100
}

fn liquidator_pays_discounted(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt:          Int,
  bonus_percent: Int,
) -> Bool {
  let required = discounted_debt(debt, bonus_percent)
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= required
}

validator cdp_liquidation_bonus {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liquidation_ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_discounted_debt_zero_bonus(debt via fuzz.int_at_least(1)) {
  discounted_debt(debt, 0) == debt
}

test prop_discounted_debt_less_than_full(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(1, 50)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) < debt
}

test prop_discounted_debt_non_negative(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) >= 0
}

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  is_undercollateralized(debt * 119, debt * 100, 120)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// Zero debt means is_undercollateralized must return False regardless of
// collateral and ratio, because the guard `debt > 0` fails.
test prop_zero_debt_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_at_least(1)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// When collateral * 100 >= debt * ratio the position is healthy, so
// is_undercollateralized must return False.
// Choose collateral = debt * ratio so collateral*100 == debt*ratio*100 >= debt*ratio.
test prop_overcollateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(1, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral = debt * ratio  =>  collateral * 100 = debt * ratio * 100
  // which is >= debt * ratio for ratio >= 1, so NOT undercollateralized
  expect is_undercollateralized(debt * ratio, debt, ratio)
}

// liquidator_pays_discounted with an empty outputs list always returns False
// when required > 0 (i.e. debt >= 1 and bonus_percent <= 99), because paid=0.
test prop_no_outputs_fails_liquidator_pays(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) fail {
  let (debt, bonus) = vals
  // paid = 0, required = discounted_debt(debt, bonus) >= 1
  expect liquidator_pays_discounted([], dummy_output(), debt, bonus)
}

// When bonus_percent == 100 the discounted debt is 0, so required == 0 and
// any payment suffices — BUT for bonus > 100 the formula goes negative which
// means paid (0) >= required (negative) is True, so we stay in 0-99.
// Instead target: small debt (1), bonus 0, required 1, paid 0 → False.
test prop_underpayment_rejected() fail {
  // debt=1, bonus=0 → required=1; outputs empty → paid=0; 0 >= 1 is False
  expect liquidator_pays_discounted([], dummy_output(), 1, 0)
}

fn dummy_output() -> Output {
  Output {
    address: cardano/address.from_verification_key(#"00"),
    value: assets.zero,
    datum: cardano/transaction.NoDatum,
    reference_script: None,
  }
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:        ByteArray,
  collateral:   Int,
  debt:         Int,
  warn_ratio:   Int,
  liq_ratio:    Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Position is in warning zone: below warn_ratio but above liq_ratio
fn in_warning_zone(
  collateral: Int,
  debt:       Int,
  warn_ratio: Int,
  liq_ratio:  Int,
) -> Bool {
  is_undercollateralized(collateral, debt, warn_ratio) && !is_undercollateralized(
    collateral,
    debt,
    liq_ratio,
  )
}

fn liquidator_pays_debt(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt_lovelace: Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_soft_threshold {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liq_ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_warning_zone_between_ratios(debt via fuzz.int_at_least(1)) {
  // collateral at 115% — below warn(120) but above liq(110)
  in_warning_zone(debt * 115, debt * 100, 120, 110)
}

test prop_below_liq_ratio_not_warning(debt via fuzz.int_at_least(1)) {
  // collateral at 105% — below both ratios, so not in warning zone
  !in_warning_zone(debt * 105, debt * 100, 120, 110)
}

test prop_above_warn_ratio_not_warning(debt via fuzz.int_at_least(1)) {
  // collateral at 130% — above warn ratio, not in warning zone
  !in_warning_zone(debt * 130, debt * 100, 120, 110)
}

test prop_undercollateralized_no_debt(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_at_least(1)),
) {
  let (collateral, ratio) = vals
  !is_undercollateralized(collateral, 0, ratio)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// A position well above the warn_ratio is NOT undercollateralized,
// so is_undercollateralized must return False for any debt >= 1
// when collateral * 100 >= debt * ratio (200 * 100 = 20000 >= debt * 150 for debt <= 133).
// We keep debt in [1, 100] so that collateral=200 always satisfies 200*100 >= debt*150.
test prop_overcollateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(1, 133)),
) fail {
  let (ratio, debt) = vals
  // collateral=200 * 100 = 20000, debt * ratio <= 100 * 133 = 13300 — always overcollateralized
  // Wait: we need is_undercollateralized to return False, i.e. 200*100 >= debt*ratio
  // debt in [1,100], ratio in [1,133] → debt*ratio <= 13300 < 20000  ✓
  expect is_undercollateralized(200, debt, ratio)
}

// Zero debt must never be considered undercollateralized regardless of collateral and ratio
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_between(0, 1000), fuzz.int_between(1, 300)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// A position above the warn_ratio is never in the warning zone.
// debt in [1,100], collateral = debt * 200 → ratio 200% > warn_ratio 150% > liq_ratio 120%
test prop_safe_position_not_in_warning_zone(
  debt via fuzz.int_between(1, 100),
) fail {
  // collateral * 100 = debt * 200 * 100 = debt * 20000 >= debt * 150  → NOT undercollateralized at warn
  // so in_warning_zone must be False
  expect in_warning_zone(debt * 200, debt * 100, 150, 120)
}

// When no outputs are provided, liquidator_pays_debt must return False for any positive debt
test prop_no_outputs_liquidator_pays_nothing(
  debt via fuzz.int_at_least(1),
) fail {
  // paid = 0 < debt (debt >= 1), so liquidator_pays_debt returns False
  // We need a dummy owner_addr Output — construct one with an impossible address check.
  // Since outputs is [], foldl returns 0, and 0 >= debt is False for debt >= 1.
  expect liquidator_pays_debt([], Output { address: cardano/address.from_script(#""), value: cardano/assets.zero, datum: cardano/transaction.NoDatum, reference_script: None }, debt)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  min_collateral:    Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Position must have at least min_collateral to be liquidatable (dust guard)
fn is_liquidatable(
  collateral:     Int,
  debt:           Int,
  ratio:          Int,
  min_collateral: Int,
) -> Bool {
  collateral >= min_collateral && is_undercollateralized(collateral, debt, ratio)
}

fn liquidator_pays_debt(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt_lovelace: Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_dust_guard {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_liquidatable(
          d.collateral,
          d.debt,
          d.liquidation_ratio,
          d.min_collateral,
        )
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_dust_guard_undercollateralized_above_min(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  is_liquidatable(collateral, debt * 100, 120, 1)
}

test prop_dust_guard_below_min_not_liquidatable(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  !is_liquidatable(collateral, debt * 100, 120, collateral + 1)
}

test prop_dust_guard_overcollateralized_not_liquidatable(debt via fuzz.int_at_least(1)) {
  !is_liquidatable(debt * 150, debt * 100, 120, 1)
}

test prop_undercollateralized_inverse(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (collateral, debt) = vals
  let ratio = 150
  !(is_undercollateralized(collateral, debt, ratio) && collateral * 100 >= debt * ratio)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// A well-collateralized position (collateral * 100 >= debt * ratio) must never
/// be flagged as undercollateralized.
test prop_overcollateralized_not_undercollateralized(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral * 100 = debt * 200, which is >= debt * 150, so NOT undercollateralized
  expect is_undercollateralized(debt * 2, debt, 150)
}

/// A position whose collateral falls below min_collateral must never be
/// liquidatable, even if it is technically undercollateralized.
test prop_below_min_collateral_not_liquidatable(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(101, 500)),
) fail {
  let (collateral, debt) = vals
  // ratio=150: collateral * 100 < debt * 150 when debt > collateral (holds here)
  // min_collateral = collateral + 1 so collateral < min_collateral → not liquidatable
  expect is_liquidatable(collateral, debt, 150, collateral + 1)
}

/// Zero-debt positions are never undercollateralized regardless of collateral.
test prop_zero_debt_not_undercollateralized(
  collateral via fuzz.int_between(0, 10000),
) fail {
  expect is_undercollateralized(collateral, 0, 150)
}

/// liquidator_pays_debt must reject when no outputs are provided, for any
/// positive debt amount.
test prop_no_outputs_debt_not_paid(
  debt via fuzz.int_between(1, 1000000),
) fail {
  // With an empty output list the fold yields 0, which is < debt (>= 1)
  // We need a dummy owner_addr Output; use a known-bad placeholder by
  // checking the helper directly with an empty list and a non-zero debt.
  expect liquidator_pays_debt([], Output { address: cardano/address.from_verification_key(#""), value: cardano/assets.zero, datum: cardano/transaction.NoDatum, reference_script: None }, debt)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:        ByteArray,
  collateral:   Int,
  debt:         Int,
  asset_tier:   Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

/// Return the liquidation ratio for the asset tier (1=stable, 2=volatile, 3=exotic)
fn tier_ratio(tier: Int) -> Int {
  if tier == 1 {
    110
  } else if tier == 2 {
    130
  } else {
    150
  }
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

fn liquidator_pays_debt(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt_lovelace: Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_tiered_ratio {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let ratio = tier_ratio(d.asset_tier)
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate -> is_undercollateralized(d.collateral, d.debt, ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_tier1_ratio() {
  tier_ratio(1) == 110
}

test prop_tier2_ratio() {
  tier_ratio(2) == 130
}

test prop_tier3_ratio() {
  tier_ratio(3) == 150
}

test prop_tiered_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(1, 3)),
) {
  let (debt, tier) = vals
  let ratio = tier_ratio(tier)
  // just below the ratio threshold
  is_undercollateralized(debt * (ratio - 1), debt * 100, ratio)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// Zero debt means is_undercollateralized must return False regardless of collateral.
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 3)),
) fail {
  let (collateral, tier) = vals
  let ratio = tier_ratio(tier)
  expect is_undercollateralized(collateral, 0, ratio)
}

// A perfectly collateralised position (collateral * 100 == debt * ratio) is NOT
// undercollateralised — the condition requires strict less-than.
test prop_exact_ratio_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 3), fuzz.int_between(1, 1000)),
) fail {
  let (tier, debt) = vals
  let ratio = tier_ratio(tier)
  // collateral * 100 == debt * ratio  →  NOT undercollateralized
  let collateral = debt * ratio
  expect is_undercollateralized(collateral, debt, ratio)
}

// When collateral is far above the threshold the position is healthy, not liquidatable.
test prop_overcollateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 3)),
) fail {
  let (debt, tier) = vals
  let ratio = tier_ratio(tier)
  // collateral * 100 == debt * ratio * 2  →  twice the required collateral
  let collateral = debt * ratio * 2
  expect is_undercollateralized(collateral, debt, ratio)
}

// liquidator_pays_debt must return False when outputs list is empty (paid == 0)
// and debt_lovelace is at least 1.
test prop_no_outputs_liquidator_fails(
  debt_lovelace via fuzz.int_at_least(1),
) fail {
  // We need a dummy owner_addr Output; construct the simplest possible one.
  // Because outputs is [], the fold returns 0, which is < debt_lovelace (≥ 1).
  let dummy_addr =
    cardano/address.from_verification_key(#"00")
  let dummy_output =
    Output {
      address: dummy_addr,
      value: cardano/assets.zero,
      datum: cardano/transaction.NoDatum,
      reference_script: None,
    }
  expect liquidator_pays_debt([], dummy_output, debt_lovelace)
}

use aiken/collection/list
use aiken/fuzz
use aiken/interval
use cardano/transaction.{OutputReference, Transaction}
pub type LoanDatum {
  lender:   ByteArray,
  borrower: ByteArray,
  amount:   Int,
  deadline: Int,
}

pub type LoanRedeemer {
  Repay
  Reclaim
}

/// True when the tx validity range is entirely after the deadline
fn is_after_deadline(
  validity_range: interval.Interval,
  deadline:       Int,
) -> Bool {
  interval.is_entirely_after(validity_range, deadline)
}

validator loan_deadline {
  spend(
    datum: Option<LoanDatum>,
    redeemer: LoanRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay ->
        // Borrower repays before deadline — they must sign
        !is_after_deadline(self.validity_range, d.deadline)
          && list.has(self.extra_signatories, d.borrower)
      Reclaim ->
        // Lender reclaims collateral only after deadline passes
        is_after_deadline(self.validity_range, d.deadline)
          && list.has(self.extra_signatories, d.lender)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_is_after_deadline_entirely_after(
  deadline via fuzz.int_between(0, 999),
) {
  // interval.after(1000) → lower bound = 1000, no upper bound
  is_after_deadline(interval.after(1000), deadline)
}

test prop_is_after_deadline_entirely_before(
  deadline via fuzz.int_between(1001, 2000),
) {
  // interval entirely before deadline → not after
  !is_after_deadline(interval.before(1000), deadline)
}

test prop_repay_reclaim_mutually_exclusive(
  deadline via fuzz.int_between(1, 1000),
) {
  let range_after  = interval.after(deadline + 1)
  let range_before = interval.before(deadline)
  let after_flag  = is_after_deadline(range_after, deadline)
  let before_flag = is_after_deadline(range_before, deadline)
  after_flag && !before_flag
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// A range that ends strictly before the deadline is NOT entirely after it.
/// For any deadline >= 1001, interval.before(1000) ends at 999 < deadline,
/// so is_after_deadline must return False.
test prop_before_range_never_after_deadline(
  deadline via fuzz.int_between(1001, 9999),
) fail {
  expect is_after_deadline(interval.before(1000), deadline)
}

/// A range starting exactly AT the deadline is not entirely AFTER it
/// (entirely_after requires strictly greater than the deadline).
/// interval.after(deadline) has lower bound == deadline, so it is not
/// entirely after deadline — the function must return False.
test prop_range_starting_at_deadline_not_after(
  deadline via fuzz.int_between(0, 9999),
) fail {
  expect is_after_deadline(interval.after(deadline), deadline)
}

/// The fully-unbounded interval (everything) is not entirely after any
/// finite deadline because it includes values at or before the deadline.
test prop_unbounded_interval_not_after_deadline(
  deadline via fuzz.int_between(0, 9999),
) fail {
  expect is_after_deadline(interval.everything(), deadline)
}

/// A range that ends well before the deadline can never be entirely after it.
/// Here the range is [0, deadline-1], constructed as interval.before(deadline).
/// Because it terminates before the deadline, is_after_deadline must be False.
test prop_range_ending_before_deadline_not_after(
  deadline via fuzz.int_between(1, 9999),
) fail {
  expect is_after_deadline(interval.before(deadline), deadline)
}

use aiken/collection/list
use aiken/fuzz
use aiken/interval
use cardano/transaction.{OutputReference, Transaction}
pub type LoanDatum {
  lender:     ByteArray,
  borrower:   ByteArray,
  amount:     Int,
  start_date: Int,
  deadline:   Int,
}

pub type LoanRedeemer {
  Cancel
  Repay
  Reclaim
}

fn is_after_deadline(validity_range: interval.Interval, deadline: Int) -> Bool {
  interval.is_entirely_after(validity_range, deadline)
}

/// Lender can cancel only before the loan start date (pre-activation)
fn is_before_start(validity_range: interval.Interval, start_date: Int) -> Bool {
  !is_after_deadline(validity_range, start_date)
}

validator loan_lender_cancel {
  spend(
    datum: Option<LoanDatum>,
    redeemer: LoanRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Cancel ->
        is_before_start(self.validity_range, d.start_date) && list.has(
          self.extra_signatories,
          d.lender,
        )
      Repay ->
        !is_after_deadline(self.validity_range, d.deadline) && list.has(
          self.extra_signatories,
          d.borrower,
        )
      Reclaim ->
        is_after_deadline(self.validity_range, d.deadline) && list.has(
          self.extra_signatories,
          d.lender,
        )
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_cancel_before_start(start via fuzz.int_between(1001, 2000)) {
  is_before_start(interval.before(1000), start)
}

test prop_cancel_after_start_false(start via fuzz.int_between(0, 999)) {
  !is_before_start(interval.after(1000), start)
}

test prop_reclaim_after_deadline(deadline via fuzz.int_between(0, 999)) {
  is_after_deadline(interval.after(1000), deadline)
}

test prop_repay_reclaim_exclusive(deadline via fuzz.int_between(1, 1000)) {
  let after  = is_after_deadline(interval.after(deadline + 1), deadline)
  let before = is_after_deadline(interval.before(deadline), deadline)
  after && !before
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// is_before_start returns False when validity range is entirely after start_date.
/// interval.after(1000) is entirely after any start_date <= 999.
test prop_is_before_start_rejects_past_start(
  start via fuzz.int_between(0, 999),
) fail {
  expect is_before_start(interval.after(1000), start)
}

/// is_after_deadline returns False when validity range ends before the deadline.
/// interval.before(500) is NOT entirely after any deadline >= 500.
test prop_is_after_deadline_rejects_before_deadline(
  deadline via fuzz.int_between(500, 2000),
) fail {
  expect is_after_deadline(interval.before(500), deadline)
}

/// is_before_start returns False for a point interval exactly at start_date
/// when the range is entirely after that point (interval.after(start) means
/// the range starts strictly after start, so start is not before start).
test prop_is_before_start_rejects_exact_start(
  start via fuzz.int_between(0, 1000),
) fail {
  // interval.after(start) is entirely after `start`, so is_after_deadline
  // returns True, making is_before_start return False
  expect is_before_start(interval.after(start), start)
}

/// is_after_deadline returns False for an entirely-before range regardless of deadline.
/// interval.before(0) ends before any positive deadline.
test prop_is_after_deadline_rejects_strictly_before(
  deadline via fuzz.int_between(1, 500),
) fail {
  expect is_after_deadline(interval.before(0), deadline)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type State {
  Idle
  Active
  Locked
  Closing
}

pub type StateRedeemer {
  Advance
  Reset
  Terminate
}

pub type MachineDatum {
  state:        State,
  admin:        VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
}

/// Valid transitions: Idle→Active, Active→Locked, Locked→Closing
fn valid_transition(from: State, to: State, redeemer: StateRedeemer) -> Bool {
  when redeemer is {
    Advance ->
      when from is {
        Idle    -> to == Active
        Active  -> to == Locked
        Locked  -> to == Closing
        Closing -> False
      }
    Reset     -> to == Idle
    Terminate -> to == Closing
  }
}

/// The beacon NFT must be present in the continuing output
fn beacon_preserved(
  outputs:      List<Output>,
  own_addr:     address.Address,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn state_from_output(output: Output) -> Option<MachineDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: MachineDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_state_machine {
  spend(
    datum: Option<MachineDatum>,
    redeemer: StateRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    // Find own input to get address
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    // Find continuing output with new datum
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = state_from_output(next_output)
    // Validate
    valid_transition(d.state, next_d.state, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
      && (
        when redeemer is {
          Advance -> True
          Reset   -> list.has(self.extra_signatories, d.admin)
          Terminate -> list.has(self.extra_signatories, d.admin)
        }
      )
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_valid_transition_advance_idle() {
  valid_transition(Idle, Active, Advance)
}

test prop_valid_transition_advance_active() {
  valid_transition(Active, Locked, Advance)
}

test prop_valid_transition_advance_locked() {
  valid_transition(Locked, Closing, Advance)
}

test prop_valid_transition_closing_advance_fails() {
  !valid_transition(Closing, Idle, Advance)
}

test prop_valid_transition_reset_always_to_idle() {
  valid_transition(Active, Idle, Reset)
    && valid_transition(Locked, Idle, Reset)
    && valid_transition(Closing, Idle, Reset)
}

test prop_valid_transition_wrong_target_fails() {
  !valid_transition(Idle, Locked, Advance)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// Advancing from Closing is never valid regardless of target state
test prop_closing_advance_always_fails() fail {
  expect valid_transition(Closing, Closing, Advance)
}

/// Reset must land on Idle; any non-Idle target must be rejected.
/// Active, Locked, and Closing are all non-Idle, so resetting to Closing fails.
test prop_reset_to_non_idle_fails() fail {
  expect valid_transition(Active, Closing, Reset)
}

/// Advance from Idle must go to Active; going to Locked is always wrong.
test prop_advance_idle_wrong_target_fails() fail {
  expect valid_transition(Idle, Locked, Advance)
}

/// beacon_preserved returns False when the output list is empty,
/// no matter what policy/name is requested.
test prop_beacon_not_preserved_in_empty_outputs(
  addr via cfuzz.address(),
  policy via cfuzz.policy_id(),
  name via cfuzz.asset_name(),
) fail {
  expect beacon_preserved([], addr, policy, name)
}
